(game "Refreshing Rose Badger"
    (players 2)
    (equipment 
        (board (square 5))
    ) 

    (rules 
        (start
            (place P1 (center))
        )
        (play
            (repeat (P1 P2)
                (place (destination empty) 
                    (effects 
                        (capture (adjacent occupied) increment_score:true)
                        (move (adjacent occupied) destination:empty)
                    )
                    (result 
                        (not (line 5))
                    )
                )
                (force_pass)
            )
        )

        (end 
            (if (line 5) (mover win))
            (if (full_board) (draw))    
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

